// Build the WhatsApp text + email subject/body from the Supabase trigger payload.
const TYPES = {
  professional: 'פנייה מקצועית',
  connection: 'הצעת חיבור',
  partnership: 'שותפות מימון',
  share: 'שתפו אותנו'
};

const body = $input.first().json.body || $input.first().json;
const d = body.data || {};
const link = body.link || null;

let linkLine = '';
if (link) {
  if (link.source_type === 'curated') {
    const role = link.curated_for_role ? ' (' + link.curated_for_role + ')' : '';
    linkLine = '🔗 הגיע מ: ' + (link.curated_for_name || '') + role;
  } else if (link.source_type === 'self') {
    linkLine = '🔁 הגיע ע"י שיתוף של: ' + (link.self_optional_name || 'אנונימי');
  }
}

const lines = [
  '🎯 טופס חדש — ' + (TYPES[body.type] || body.type),
  d.name ? '👤 ' + d.name : null,
  d.email ? '📧 ' + d.email : null,
  d.phone ? '📞 ' + d.phone : null,
  linkLine || null,
  '',
  d.message ? '💬 ' + String(d.message).slice(0, 400) : null,
  d.content ? '💬 ' + String(d.content).slice(0, 400) : null
].filter(Boolean);

const waText = lines.join('\n');
const subject = 'בית אברהם — ' + (TYPES[body.type] || body.type) + ' — ' + (d.name || 'אנונימי');

const rows = Object.entries(d).map(([k, v]) => '<tr><td style="padding:6px 12px;color:#666;">' + k + '</td><td style="padding:6px 12px;">' + String(v).replace(/[<>&]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c])) + '</td></tr>').join('');
const html = '<div style="direction:rtl;text-align:right;font-family:Heebo,Arial,sans-serif;">' +
  '<h2>' + subject + '</h2>' +
  (linkLine ? '<p>' + linkLine + '</p>' : '') +
  '<table style="border-collapse:collapse;border:1px solid #eee;">' + rows + '</table>' +
  '<p style="color:#888;font-size:12px;margin-top:24px;">submission_id: ' + body.submission_id + '<br>session_id: ' + body.session_id + '<br>short_code: ' + (body.short_code || '(none)') + '</p>' +
  '</div>';

return [{ json: { wa_text: waText, email_subject: subject, email_html: html, wa_to: '972515120079', email_to: 'avi@futureflow.co.il', raw: body } }];
